"use strict";(self.webpackChunkalgorithms_way23_ru=self.webpackChunkalgorithms_way23_ru||[]).push([[3680],{2083:(D,B,e)=>{e.r(B),e.d(B,{data:()=>l});const l=JSON.parse('{"key":"v-74625e13","path":"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F/%D1%88%D0%B0%D0%BF%D0%BE%D0%B2%D0%B0%D0%BB-%D0%BF%D1%80%D0%B5%D0%B4%D0%B5%D0%BB%D1%8B-%D1%80%D0%B0%D0%B7%D0%B2%D0%B8%D1%82%D0%B8%D1%8F-%D1%81%D0%B8%D1%81%D1%82%D0%B5%D0%BC-%D1%83%D0%BF%D1%80%D0%B0%D0%B2%D0%BB%D0%B5%D0%BD%D0%B8%D1%8F.html","title":"Пределы развития систем управления","lang":"ru-RU","frontmatter":{},"excerpt":"","headers":[],"git":{"updatedTime":1730483869000},"filePathRelative":"глушковские-чтения/шаповал-пределы-развития-систем-управления.md"}')},909:(D,B,e)=>{e.r(B),e.d(B,{default:()=>p});var l=e(6252);const t=(0,l._)("h1",{id:"пределы-развития-систем-управления",tabindex:"-1"},[(0,l._)("a",{class:"header-anchor",href:"#пределы-развития-систем-управления","aria-hidden":"true"},"#"),(0,l.Uk)(" Пределы развития систем управления")],-1),a=(0,l._)("p",null,"Шаповал А. П. (г . Хмельницкий).",-1),r=(0,l._)("p",null,"Современная экономика требует современного управления. Причем такого, которое основывается на активном и сознательном участии каждого субъекта, включённого в процесс производства, обмена и распределения общественного продукта. Современное управление должно применять постоянно совершенствующиеся средства и методы, соответствующие постоянно усложняющемуся процессу производства. Автоматизация и роботизация производства с необходимостью влекут за собой автоматизацию управления. И не только на отдельно взятом производстве или отрасли, но и во всей стране, а также группе стран, и в перспективе во всём мире. Поэтому опыт создания автоматизированной системы управления экономикой СССР, накопленный советским учёным-кибернетиком академиком В. М. Глушковым будет всегда востребован. К нему всегда будут обращаться при создании таких систем, где бы и когда бы их не создавали.",-1),n=(0,l._)("p",null,"То, что не смогла сделать социалистическая экономика в СССР, а именно, создать единую, автоматизированную систему своего управления, пытается сделать поздний капитализм в лице транснациональных корпораций. С их помощью управление экономикой перешагнуло узкие рамки национальных государств и стало транснациональным, мировым. Но, перейдя один предел, капитал упёрся в следующий — корпоративный. Системы управления производством, распределением, торговлей товарами теперь формируются как наднациональные, но всё-таки остаются ограниченными пределами отдельно взятой корпорации, т.е. в той или иной степени замкнутыми, стеснёнными определёнными рамками. Как и раньше они завязаны на интересах и собственности отдельных представителей мира капитала. Пусть даже самых крупных и объединённых в наднациональные, международные, межгосударственные группы. И всё же — разобщённых и индивидуализированных. Пока их интересы совпадают,— они вместе и находятся в пределах единых систем управления. Но как только интересы идут врозь, как правило это случается во время очередного кризиса, рушатся все связи и объединения, а за ними, соответственно, идут в небытие и системы управления.",-1),u=(0,l._)("p",null,"Отсюда встаёт главный предел в развитии систем управления капиталистической экономикой — это её частнособственнический, товарный характер. Вот почему, до сих пор не создана ни в одной стране или группе стран общегосударственная автоматизированная система управления экономикой (ОГАС). Интересы разные. У одних производителей, торговцев, служащих — одни, у других — другие. В экономической системе, где главным стимулом является прибыль, всегда одни хотят получить преимущества за счёт других, нажиться на них, обобрать, разорить тех, кто является, по сути, их конкурентами в извечной борьбе за «лучшее место под солнцем». Все вместе взятые, они в принципе не могут работать под единым руководством ради одной цели.",-1),d=(0,l._)("p",null,"Необходимо отметить, что и советская экономика не смогла перешагнуть этот предел. Да, она была социалистическая или иными словами, в нашем понимании,— переходной, т. е. пытавшейся преодолеть свою товарность и частнособственнические отношения. Но, завершить переход всё же не смогла. Поэтому, и произошёл откат назад к капитализму со всеми вытекающими из него тяжёлыми социальными последствиями. Одни не хотели выпускать власть из своих рук, справедливо полагая, что при создании автоматизированной системы управления будут попросту не нужны со своими некомпетентными и демагогическими указаниями. Другие панически боялись контроля над своими действиями со стороны всего общества, относясь к занимаемым должностям и «креслам» как к личной собственности. Третьи в силу своих умственных «способностей» или, скорее, изъянов не могли понять необходимости такой системы. Четвёртые сознательно двигали страну в сторону капитализма прикрываясь теоретическим словоблудием и преследуя собственную выгоду. В общем, все они вместе составляли тот субъективный фактор, который при активной поддержке из-вне разрушил социализм в СССР вместе с отдельными элементами (которые всё-таки удалось построить несмотря на колоссальное противодействие) автоматизированной системы управления.",-1),i=(0,l._)("p",null,"Тем не менее, попытки усовершенствования систем управления различными процессами, автоматизации целых сфер жизнедеятельности человека, происходят, несмотря ни на что. В последние два десятилетия эти попытки осуществляются на основе интернета и развития социальных сетей. Но и тут частнособственнические отношения дают о себе знать. И как только интересы государства или отдельных его слоёв, которые находятся у власти и естественно желают её сохранить как можно дольше, приходят в противоречие с интересами всего общества, тут же начинаются попытки власть имущих взять под контроль всемирную сеть, не допуская пользователей к определённым её ресурсам. Пределы развития и здесь дают о себе знать.",-1),h={},p=(0,e(3744).Z)(h,[["render",function(D,B){const e=(0,l.up)("RouterLink");return(0,l.wg)(),(0,l.iD)("div",null,[t,a,(0,l._)("p",null,[(0,l.Uk)("Из материалов конференции "),(0,l.Wm)(e,{to:"/%D0%B3%D0%BB%D1%83%D1%88%D0%BA%D0%BE%D0%B2%D1%81%D0%BA%D0%B8%D0%B5-%D1%87%D1%82%D0%B5%D0%BD%D0%B8%D1%8F.html"},{default:(0,l.w5)((()=>[(0,l.Uk)("«Глушковские чтения»")])),_:1}),(0,l.Uk)(" 2014 года.")]),r,n,u,d,i])}]])}}]);